<?php $editing=!!$category; ?><section class="admin-page-head"><div><p class="eyebrow">CATALOG / CATEGORIE</p><h1><?= $editing?'Editează categoria':'Categorie nouă' ?></h1></div></section><form class="admin-form-layout" enctype="multipart/form-data" method="post" action="<?= e(url($editing?'/admin/categorii/'.$category['id']:'/admin/categorii')) ?>"><?= csrf_field() ?><div><section class="admin-panel"><h2>Informații generale</h2><div class="admin-form-grid"><label>Nume<input name="name" required value="<?= e($category['name']??'') ?>"></label><label>Slug<input name="slug" value="<?= e($category['slug']??'') ?>"></label><label>Categorie părinte<select name="parent_id"><option value="">Fără părinte</option><?php foreach($parents as $parent): if((int)($category['id']??0)===(int)$parent['id'])continue; ?><option value="<?= (int)$parent['id'] ?>" <?= (int)($category['parent_id']??0)===(int)$parent['id']?'selected':'' ?>><?= e($parent['name']) ?></option><?php endforeach; ?></select></label><label>Ordine<input type="number" name="sort_order" value="<?= (int)($category['sort_order']??0) ?>"></label><label class="wide">Descriere<textarea name="description"><?= e($category['description']??'') ?></textarea></label></div></section><section class="admin-panel"><h2>SEO</h2><div class="admin-form-grid"><label class="wide">Meta title<input name="seo_title" value="<?= e($category['seo_title']??'') ?>"></label><label class="wide">Meta description<textarea name="seo_description"><?= e($category['seo_description']??'') ?></textarea></label></div></section></div><aside><section class="admin-panel"><h2>Publicare</h2><label class="check-label"><input type="checkbox" name="is_active" value="1" <?= !isset($category['is_active'])||$category['is_active']?'checked':'' ?>> Categorie activă</label><label class="check-label"><input type="checkbox" name="show_in_menu" value="1" <?= !isset($category['show_in_menu'])||$category['show_in_menu']?'checked':'' ?>> Afișează în meniu</label><button class="admin-button" type="submit">Salvează categoria</button></section><section class="admin-panel"><h2>Imagine categorie</h2><input type="file" name="image" accept="image/jpeg,image/png,image/webp"></section></aside></form>

